INSERT INTO `feedbacks` VALUES (1,3,NULL,NULL,'2025-10-17 09:34:09.548389','2025-10-17 09:34:09.548389',NULL,'0199f004-7b08-752f-bf41-ca1f458b0f8c',3,'saran','tambahkan lokasi dan user agar lebih jelas keberadaan asset itu di mana, dipegang siapa. terimakasih','new',NULL,'[\"feedback/0199f004-7ae5-760e-8cdd-d090eed6f4cd.png\"]'),(2,3,NULL,NULL,'2025-10-17 09:37:40.789937','2025-10-17 09:37:40.789937',NULL,'0199f007-b433-7312-ae4e-8f19c3f00207',3,'saran','ketika diklik di grafiknya langsung masuk ke data asset tersebut, tks','new',NULL,'[\"feedback/0199f007-b41e-70ec-bfea-898f789fdf35.png\"]'),(3,3,NULL,NULL,'2025-10-17 09:38:59.883497','2025-10-17 09:38:59.883497',NULL,'0199f008-e929-77db-aedb-adcc8765a235',3,'saran','Tambahkan keterangan dibawah nama asset dan jumlah asset dan bisa filter berdasarkan periode/tanggal pembelian. tks','new',NULL,'[\"feedback/0199f008-e902-7788-a3f3-707164c20d20.png\"]'),(4,3,NULL,NULL,'2025-10-17 09:41:36.334653','2025-10-17 09:41:36.334653',NULL,'0199f00b-4c4c-7181-925f-1de0647dd6c3',3,'saran','Semua keterangan bisa diklik ke detail, misalnya kategori, sub kategori atau buat tanda seru diatasnya ketika diklik tanda serunya isinya keterangan apa itu kategory apa itu yang termasuk sub kategori','new',NULL,'[\"feedback/0199f00b-4c1c-7453-895e-0c5838c05488.png\"]'),(5,3,NULL,NULL,'2025-10-17 09:51:31.657642','2025-10-17 09:51:31.657642',NULL,'0199f014-61c6-728f-a402-1edbbceb8563',3,'keluhan','properties belum bisa diklik, dan tidak tau fungsinya utk apa ya?\r\nsebaiknya ada tanda seru yang bisa menjelaskan apa itu, seperti dinusawork (gbr terlampir)','new',NULL,'[\"feedback/0199f014-6173-70c9-8ee2-0ffdee667f68.png\",\"feedback/0199f014-6199-7468-86ea-e68773ae71cc.png\"]'),(6,3,NULL,NULL,'2025-10-17 09:55:58.519757','2025-10-17 09:55:58.519757',NULL,'0199f018-7434-701c-9231-22983c6a949d',3,'saran','Sangat bagus ya sdh ada aplikasi utk management asset, thanks ya tim, namun sebaiknya bisa menginput data asset secara masal (banyak sekaligus), templatenya didownload dulu, setelah isi upload balik. tolong di tambahkan ya tim, terimakasih.','new',NULL,'[\"feedback/0199f018-740d-735d-8468-0de8a0d25c6b.png\",\"feedback/0199f018-7423-749f-9008-3eac5452e081.png\"]'),(7,3,NULL,NULL,'2025-10-17 09:58:36.620001','2025-10-17 09:58:36.620001',NULL,'0199f01a-ddc9-74fb-b308-82aa21de4b66',3,'saran','Tambahkan menu export excel sebagai report dan bisa filter sesuai dengan kebutuhan, misalnya masa pembelian, mau lihat asset sudah berapa lama masanya, dll\r\n\r\nJika perlu koordinasi jangan sungkan ya, cari HRGA. Tks','new',NULL,'[\"feedback/0199f01a-ddb3-70e8-8daa-830f8e8a7819.png\"]'),(8,7,NULL,NULL,'2025-10-17 10:01:09.797494','2025-10-17 10:01:09.797494',NULL,'0199f01d-3423-74b8-8b84-75cf34593168',7,'saran','Dear Team, \r\ndi bagian my feedback belum ada feedback saya terlihat yang sudah saya berikan tadi, saya memberikan feedback sekitar 1 menit lalu, mungkin masih delay atau lost, tolong bantu cek kembali ya terimakasih','new',NULL,'[\"feedback/0199f01d-340f-7335-9449-919652e943fa.png\"]'),(9,8,NULL,NULL,'2025-10-17 10:41:52.764377','2025-10-17 10:41:52.764377',NULL,'0199f042-7afa-740b-80ac-e5cd85e53328',8,'pujian','bagus','new',NULL,'[\"feedback/0199f042-7abc-7762-b46a-b94572a76396.png\"]'),(10,1,NULL,NULL,'2025-10-17 10:46:02.703116','2025-10-17 10:46:02.703116',NULL,'0199f046-4b4d-743f-b0f1-55b98af4c8d1',1,'pujian','testing123','new',NULL,'[\"feedback/0199f046-4b29-75ec-a3f9-f6394f7e638f.png\"]'),(11,7,NULL,NULL,'2025-11-03 11:12:31.224459','2025-11-03 11:12:31.224459',NULL,'019a47ea-a474-7058-879c-126d997005a6',7,'saran','boleh ditambahkan fitu impor untuk data data asset yang mau di add secara massal, terimakasih','new',NULL,'[\"feedback/019a47ea-a445-72b4-9e90-2891de609e5d.png\"]'),(12,7,NULL,NULL,'2025-11-19 15:23:46.461721','2025-11-19 15:23:46.461721',NULL,'019a9b36-6c19-7754-8ebc-c6ec262ef484',7,'saran','bang, boleh kah di tambahkan fitur untuk show 10/25/50/100/all seperti yang ada pada IS5\r\n\r\nThanyou bang','new',NULL,'[\"feedback/019a9b36-6b99-7489-aaf2-302f14f67292.png\",\"feedback/019a9b36-6be6-737a-b7ef-32c6f9319606.png\",\"feedback/019a9b36-6bff-725c-ac65-0ab5aa010806.png\"]'),(13,4,NULL,NULL,'2025-12-15 11:16:23.568234','2025-12-15 11:16:23.568234',NULL,'019b2039-480e-756d-a2c8-c39075344d72',4,'saran','saat next pagination, icon foto setiap employee sebaiknya clear/ jadi loader dulu sehingga ga kesan glitch','new',NULL,'[\"feedback/019b2039-47d7-7082-9c89-b0522d701cae.png\"]'),(14,3,NULL,NULL,'2026-01-24 03:22:56.496581','2026-01-24 03:22:56.496581',NULL,'019bec86-32df-7173-8a2e-b53a1c413b0e',3,'saran','lokasi sebaiknya selain lantai ada juga nama ruangan dan nama employee jika digunakan oleh employee, agar lebih jelas posisinya. tks','new',NULL,'[\"feedback/019bec86-32b8-74ad-8cbc-6ae98e8ab78b.png\"]'),(15,3,NULL,NULL,'2026-01-27 09:55:56.703926','2026-01-27 09:55:56.703926',NULL,'019bfd61-1507-754d-b4b6-4e94991b37d9',3,'saran','pada maintanance history ada tanggal until nya, dan kapan service lagi ada notifikasi ke user atau ke GT\r\n\r\nTerimakasih','new',NULL,'[\"feedback/019bfd61-14f0-758b-907c-77e36d639b84.png\"]'),(16,3,NULL,NULL,'2026-01-27 09:58:57.365253','2026-01-27 09:58:57.365253',NULL,'019bfd63-d6bd-7027-8573-448f09171c60',3,'saran','Sesuai kebutuhan ISO 9001: 2015\r\nTambahkan Klasifikasi:\r\nUmum/Public\r\nPrivate\r\nInternal\r\nSecret\r\n\r\nTerimakasih','new',NULL,'[\"feedback/019bfd63-d6a8-72e7-b833-5692e12eb33b.png\"]'),(17,3,NULL,NULL,'2026-01-27 10:01:50.482328','2026-01-27 10:01:50.482328',NULL,'019bfd66-7afa-76f9-8264-df65f2c87e02',3,'keluhan','Belum bisa pilih bahasa (indonesia/english)','new',NULL,'[\"feedback/019bfd66-7ad9-716c-8158-a7281ed4e735.png\"]'),(18,27,NULL,NULL,'2026-01-29 14:29:40.007546','2026-01-29 14:29:40.007546',NULL,'019c08a8-668d-74eb-85bb-b967668b9854',27,'saran','- di detail asset kolom user seharusnya buat nama pemakai','new',NULL,'[\"feedback/019c08a8-6673-70ea-919e-dcf5847b6c10.png\"]'),(19,27,NULL,NULL,